@startuml
"ProductOfferingPrice" as ProductOfferingPrice
"ProductOfferingTerm" as ProductOfferingTerm
"PricingLogicAlgorithm" as PricingLogicAlgorithm
"ProductOfferingPriceRelationship" as ProductOfferingPriceRelationship
"TaxItem" as TaxItem
"ProductSpecificationCharacteristicValueUse" as ProductSpecificationCharacteristicValueUse
"PlaceRef" as PlaceRef
"ConstraintRef" as ConstraintRef
"ProductSpecificationRef" as ProductSpecificationRef
"CharacteristicValueSpecification" as CharacteristicValueSpecification
"TargetProductSchema" as TargetProductSchema
"BundledProductOfferingPriceRelationship" as BundledProductOfferingPriceRelationship

ProductOfferingPrice --|> ProductOfferingTerm : productOfferingTerm
ProductOfferingPrice --|> PricingLogicAlgorithm : pricingLogicAlgorithm
ProductOfferingPrice --|> ProductOfferingPriceRelationship : popRelationship
ProductOfferingPrice --|> TaxItem : tax
ProductOfferingPrice --|> ProductSpecificationCharacteristicValueUse : prodSpecCharValueUse
ProductOfferingPrice --|> PlaceRef : place
ProductOfferingPrice --|> ConstraintRef : constraint

ProductSpecificationCharacteristicValueUse --|> ProductSpecificationRef : productSpecification
ProductSpecificationCharacteristicValueUse --|> CharacteristicValueSpecification : productSpecCharacteristicValue
ProductSpecificationRef --|> TargetProductSchema : targetProductSchema

BundledProductOfferingPriceRelationship --|> ProductOfferingPrice : bundledPopRelationship

ProductOfferingPrice {
  description : String
  href : String
  id : String
  isBundle : Boolean
  lastUpdate : DateTime
  lifecycleStatus : String
  name : String
  percentage : Float
  price : Money
  priceType : String
  recurringChargePeriodLength : Integer
  recurringChargePeriodType : String
  unitOfMeasure : Quantity
  validFor : TimePeriod
  version : String
  @baseType : String
  @schemaLocation : String
  @type : String
}

ProductOfferingTerm {
  description : String
  duration : Quantity
  name : String
  validFor : TimePeriod
  @baseType : String
  @schemaLocation : Uri
  @type : String
}

PricingLogicAlgorithm {
  description : String
  href : Uri
  id : String
  name : String
  plaSpecId : String
  validFor : TimePeriod
  @baseType : String
  @schemaLocation : Uri
  @type : String
}

ProductOfferingPriceRelationship {
  href : String
  id : String
  name : String
  relationshipType : String
  @baseType : String
  @schemaLocation : Uri
  @type : String
}

TaxItem {
  href : Uri
  id : String
  taxAmount : Money
  taxCategory : String
  taxRate : Float
  @baseType : String
  @schemaLocation : Uri
  @type : String
}

ProductSpecificationCharacteristicValueUse {
  description : String
  id : String
  maxCardinality : Integer
  minCardinality : Integer
  name : String
  validFor : TimePeriod
  valueType : String
  @baseType : String
  @schemaLocation : Uri
  @type : String
}

PlaceRef {
  href : Uri
  id : String
  name : String
  @baseType : String
  @referredType : String
  @schemaLocation : Uri
  @type : String
}

ConstraintRef {
  href : Uri
  id : String
  name : String
  version : String
  @baseType : String
  @referredType : String
  @schemaLocation : Uri
  @type : String
}

ProductSpecificationRef {
  href : Uri
  id : String
  name : String
  version : String
  @baseType : String
  @referredType : String
  @schemaLocation : Uri
  @type : String
}

CharacteristicValueSpecification {
  isDefault : Boolean
  rangeInterval : String
  regex : String
  unitOfMeasure : String
  validFor : TimePeriod
  value : Any
  valueFrom : Integer
  valueTo : Integer
  valueType : String
  @baseType : String
  @schemaLocation : Uri
  @type : String
}

TargetProductSchema {
  @schemaLocation : Uri [1]
  @type : String [1]
}

BundledProductOfferingPriceRelationship {
  href : String
  id : String
  name : String
  @baseType : String
  @schemaLocation : Uri
  @type : String
}

@enduml
